mapper.sql:
/* wms-outbound-obWaveMgmt-sql-oracle.xml - selectObWaveMgmtRefSql - WMS > 출고 관리 > 웨이브관리 조회 SQL */ SELECT 0 AS CHK , WH.CTKEY /*센터코드*/ , WH.OWKEY /*화주코드*/ , WH.WAHDKEY /*웨이브 공통 코드*/ , WH.WAHDDAY /*웨이브 헤더 일자*/ , WH.WARND /*웨이브회차*/ , WH.WAHDNM /*웨이브 헤더 명*/ , WH.WKTYPECD /*작업 유형 코드*/ , WH.WAWKSTATUSCD /*웨이브 작업 상태 코드*/ , (CASE WHEN COUNT(CASE WHEN WD.DELYN = 'N' THEN OH.OBHDKEY ELSE NULL END) = (SUM(CASE WHEN OH.DLVRYPRGRSTATUSCD IN ('30') AND WD.DELYN = 'N' THEN 1 ELSE 0 END)) THEN DLV.DLVRYCORPNM WHEN COUNT(CASE WHEN WD.DELYN = 'N' THEN OH.OBHDKEY ELSE NULL END) = (SUM(CASE WHEN OH.DLVRYPRGRSTATUSCD IN ('20') AND WD.DELYN = 'N' THEN 1 ELSE 0 END)) THEN DLV.DLVRYCORPNM WHEN WAWKSTATUSCD IN ('10','15') AND COUNT(CASE WHEN WD.DELYN = 'N' THEN OH.OBHDKEY ELSE NULL END) > (SUM(CASE WHEN OH.DLVRYPRGRSTATUSCD IN ('30') THEN 1 ELSE 0 END)) THEN '택배접수' ELSE DLV.DLVRYCORPNM END) AS DLVRYCORPCD /*택배접수상태*/ , CASE WHEN WH.DLVRYCORPCD IS NOT NULL AND (COUNT(CASE WHEN WD.DELYN = 'N' THEN OH.OBHDKEY ELSE NULL END) = (SUM(CASE WHEN OH.DLVRYPRGRSTATUSCD IN ('30') AND WD.DELYN = 'N' THEN 1 ELSE 0 END))) THEN 'Y' ELSE '' END AS WBLPR /*운송장 출력*/ , (CASE WHEN WH.WKTYPECD = 'DW' THEN (CASE WHEN WAWKSTATUSCD IN ('20','25') AND SUM(CASE WHEN OH.DASCELLBARCODE IS NULL OR WD.DELYN = 'Y' THEN 1 ELSE 0 END) > 0 THEN '10' WHEN WAWKSTATUSCD IN ('20','25') AND COALESCE(WH.CLASSIFPLANSNDYN, 'N') = 'N' AND COALESCE(WH.LOCPLANSNDYN, 'N') = 'N' THEN '20' WHEN WAWKSTATUSCD IN ('20','25') AND COALESCE(WH.CLASSIFPLANSNDYN, 'N') = 'Y' AND COALESCE(WH.LOCPLANSNDYN, 'N') = 'N' THEN '30' WHEN WAWKSTATUSCD IN ('30','40','50','60') OR (COALESCE(WH.CLASSIFPLANSNDYN, 'N') = 'Y' AND COALESCE(WH.LOCPLANSNDYN, 'N') = 'Y') THEN '40' ELSE '' END) WHEN WH.WKTYPECD IN ('RW','PW') THEN (CASE WHEN WAWKSTATUSCD IN ('20','25') AND COALESCE(WH.CLASSIFPLANSNDYN, 'N') = 'N' THEN '20' WHEN WAWKSTATUSCD IN ('30','40','50','60') AND COALESCE(WH.CLASSIFPLANSNDYN, 'N') = 'Y' THEN '40' ELSE '' END) ELSE '' END) AS CLASSIFIFSTATUS /*DAS셀매칭*/ , PH.PKDIVCD /*피킹유형*/ , PH.PIHDNM AS TASKLIST /*작업현황*/ , (CASE WHEN WH.PIHDKEY IS NOT NULL THEN 'Y' ELSE '' END) AS PKLIST /*피킹리스트*/ , WH.CMT /*비고*/ , WH.INSERTURKEY /*입력자*/ , WH.INSERTDATE /*입력일시*/ , WH.UPDATEURKEY /*수정자*/ , WH.UPDATEDATE /*수정일시*/ , CD1.CTCDDTNM AS WKTYPENM /*작업 유형명*/ , CD2.CTCDDTNM AS WAWKSTATUSNM /*웨이브 작업 상태명*/ , WH.PIHDKEY , WS.OB_CNT , WS.SKU , WS.PCS FROM TWORK_INFO_WA_HD WH INNER JOIN TWORK_INFO_WA_DT WD ON WH.CTKEY = WD.CTKEY AND WH.OWKEY = WD.OWKEY AND WH.WAHDKEY = WD.WAHDKEY INNER JOIN TWORK_INFO_OB_HD OH ON WD.CTKEY = OH.CTKEY AND WD.OWKEY = OH.OWKEY AND WD.OBHDKEY = OH.OBHDKEY INNER JOIN ( SELECT WH.CTKEY , WH.OWKEY , WH.WAHDKEY , COUNT(DISTINCT OD.OBHDKEY) AS OB_CNT , COUNT(DISTINCT OD.ICKEY) AS SKU , SUM(OD.EXPCTQTY) AS PCS FROM TWORK_INFO_WA_HD WH INNER JOIN TWORK_INFO_WA_DT WD ON WH.CTKEY = WD.CTKEY AND WH.OWKEY = WD.OWKEY AND WH.WAHDKEY = WD.WAHDKEY INNER JOIN TWORK_INFO_OB_HD OH ON WD.CTKEY = OH.CTKEY AND WD.OWKEY = OH.OWKEY AND WD.OBHDKEY = OH.OBHDKEY INNER JOIN TWORK_INFO_OB_DT OD ON OH.CTKEY = OD.CTKEY AND OH.OWKEY = OD.OWKEY AND OH.OBHDKEY = OD.OBHDKEY GROUP BY WH.CTKEY , WH.OWKEY , WH.WAHDKEY ) WS ON WH.CTKEY = WS.CTKEY AND WH.OWKEY = WS.OWKEY AND WH.WAHDKEY = WS.WAHDKEY LEFT OUTER JOIN TWORK_INFO_PI_HD PH ON WH.CTKEY = PH.CTKEY AND WH.OWKEY = PH.OWKEY AND WH.PIHDKEY = PH.PIHDKEY LEFT OUTER JOIN TWORK_MST_DLVRYCORP DLV ON WH.CTKEY = DLV.CTKEY AND WH.OWKEY = DLV.OWKEY AND WH.DLVRYCORPCD = DLV.DLVRYCORPCD AND DLV.DELYN = 'N' AND TO_CHAR(CURRENT_TIMESTAMP, 'YYYYMMDD') BETWEEN DLV.CNTRCTSTARTDAY AND DLV.CNTRCTCLOSEDAY LEFT OUTER JOIN TWORK_MST_CTCD_DT CD1 ON WH.CTKEY = CD1.CTKEY AND WH.WKTYPECD = CD1.CTCDDTKEY AND CD1.CTCDHDKEY = 'WKTYPECD' AND CD1.LAKEY = #{slakey} LEFT OUTER JOIN TWORK_MST_CTCD_DT CD2 ON WH.CTKEY = CD2.CTKEY AND WH.WAWKSTATUSCD = CD2.CTCDDTKEY AND CD2.CTCDHDKEY = 'WAWKSTATUSCD' AND CD2.LAKEY = #{slakey} WHERE
#{SEARCH_CONDITION}
GROUP BY WH.CTKEY /*센터코드*/ , WH.OWKEY /*화주코드*/ , WH.WAHDKEY /*웨이브 공통 코드*/ , WH.WAHDDAY /*웨이브 헤더 일자*/ , WH.WARND /*웨이브회차*/ , WH.WAHDNM /*웨이브 헤더 명*/ , WH.WKTYPECD /*작업 유형 코드*/ , WH.WAWKSTATUSCD /*웨이브 작업 상태 코드*/ , WH.DLVRYCORPCD /*택배접수*/ , DLV.DLVRYCORPNM /*택배사명*/ , WH.WKTYPECD , WH.CLASSIFPLANSNDYN , WH.LOCPLANSNDYN , PH.PKDIVCD /*피킹유형*/ , PH.PIHDNM /*피킹헤더명*/ , WH.CMT /*비고*/ , WH.INSERTURKEY /*입력자*/ , WH.INSERTDATE /*입력일시*/ , WH.UPDATEURKEY /*수정자*/ , WH.UPDATEDATE /*수정일시*/ , CD1.CTCDDTNM /*작업 유형명*/ , CD2.CTCDDTNM /*웨이브 작업 상태명*/ , WH.PIHDKEY , WS.OB_CNT , WS.SKU , WS.PCS

mapper.select:
/* wms-outbound-obWaveMgmt-sql-oracle.xml - selectObWaveMgmtCount - WMS > 출고 관리 > 웨이브관리 조회 카운트 */
WITH WA_BASE AS (

)
SELECT COUNT(1)
  FROM WA_BASE WH

/* wms-outbound-obWaveMgmt-sql-oracle.xml - selectObWaveMgmt - WMS > 출고 관리 > 웨이브관리 조회 */
#{GRIDPAGING_ROWNUMTYPE_TOP}

 ORDER BY
	   WH.WAHDKEY
	 , CAST(WH.WARND AS NUMERIC)
#{GRIDPAGING_ROWNUMTYPE_BOTTOM}

mapper.sql:
/* wms-outbound-obWaveMgmt-sql-oracle.xml - selectObWaveMgmtPopSchSql - WMS > 출고 관리 > 웨이브관리 - 생성 조회 조건 */

   AND SKU > #{edtover}


   AND PCS > #{edtover}


   AND CBM > #{edtover}


   AND WEIGHT > #{edtover}


   AND MAXLEN > #{edtover}


   AND RBRATIO > #{edtover}


   AND FBPCS > #{edtover}


   AND SKU BETWEEN #{skufr} AND #{skuto}


   AND PCS BETWEEN #{pcsfr} AND #{pcsto}


   AND CBM BETWEEN #{cbmfr} AND #{cbmto}


   AND WEIGHT BETWEEN #{weightfr} AND #{weightto}


   AND MAXLEN BETWEEN #{maxlenfr} AND #{maxlento}

/* wms-outbound-obWaveMgmt-sql-oracle.xml - selectObWaveMgmtPopRbSql - WMS > 출고 관리 > 생성 > 로봇합포 작업 계획 설정 > 로봇합포 출고 대상 SQL */ WITH OB_BASE AS ( SELECT OH.CTKEY , OH.OWKEY , OH.OBHDKEY , OH.CBM , (OH.WEIGHT / 1000) AS WEIGHT , OH.RECOMBOXBARCODE , (CASE BOX.BOXDIVCD WHEN '10' THEN BOX.BOXNM ELSE '그외' END) BOXNM , OH.ORDSEPTYPECD , IC.ROBSORTERICYN , GREATEST(COALESCE(ICUTX.WIDTH, 0), COALESCE(ICUTX.DEPTH, 0), COALESCE(ICUTX.HEIGHT, 0)) AS MAXLEN , OD.OBDTKEY , OD.ICKEY , OD.EXPCTQTY FROM TWORK_INFO_OB_HD OH INNER JOIN TWORK_INFO_OB_DT OD ON OH.CTKEY = OD.CTKEY AND OH.OWKEY = OD.OWKEY AND OH.OBHDKEY = OD.OBHDKEY INNER JOIN TWORK_MST_IC IC ON OD.CTKEY = IC.CTKEY AND OD.OWKEY = IC.OWKEY AND OD.ICKEY = IC.ICKEY INNER JOIN TWORK_MST_ICUTXTYPE ICUTX ON OD.CTKEY = ICUTX.CTKEY AND OD.OWKEY = ICUTX.OWKEY AND OD.ICKEY = ICUTX.ICKEY AND OD.ICUNITKEY = ICUTX.ICUNITKEY AND OD.UOM = ICUTX.ICUNITTYPECD INNER JOIN TWORK_MST_BOX BOX ON OH.CTKEY = BOX.CTKEY AND OH.RECOMBOXBARCODE = BOX.BOXBARCODE WHERE OH.CTKEY = #{ctkey} AND OH.OWKEY = #{owkey} AND OH.WKTYPECD = 'RW' AND OH.WAHDKEY IS NULL AND OH.OBSTATUSCD = '00' AND OH.OBHDTYPECD IN ('10','20') AND OH.OBHDDAY BETWEEN #{obhddayfr} AND #{obhddayto} ), RB_OB_INFO AS ( SELECT A.* , ROW_NUMBER() OVER(PARTITION BY RB_BOXNM ORDER BY RB_BOXNM, RB_OBHDKEY ASC) AS RK FROM ( SELECT CTKEY , OWKEY , OBHDKEY AS RB_OBHDKEY /*릴리즈코드*/ , BOXNM AS RB_BOXNM , CBM , WEIGHT , COUNT(ICKEY) AS SKU , SUM(EXPCTQTY) AS PCS , MAX(MAXLEN) AS MAXLEN , ROUND(COUNT(CASE WHEN ROBSORTERICYN = 'Y' THEN 1 END) * 100 / COUNT(*), 0) AS RBRATIO , SUM(CASE WHEN ROBSORTERICYN = 'N' THEN EXPCTQTY ELSE 0 END) AS FBPCS , COUNT(OBDTKEY) AS OBDT_CNT FROM OB_BASE WHERE ORDSEPTYPECD = '30' GROUP BY CTKEY , OWKEY , OBHDKEY /*릴리즈코드*/ , BOXNM , CBM , WEIGHT ) A WHERE 1=1
), RB_ITEM_RANK AS ( /* [1단계] 품목코드별 등장 건수 순위 */ SELECT DT.CTKEY , DT.OWKEY , DT.ICKEY , HD.RB_BOXNM , COUNT(DISTINCT DT.OBHDKEY) AS OBHD_CNT , ROW_NUMBER() OVER(PARTITION BY HD.RB_BOXNM ORDER BY COUNT(DISTINCT DT.OBHDKEY) DESC) AS ITEM_RK FROM RB_OB_INFO HD INNER JOIN OB_BASE DT ON HD.CTKEY = DT.CTKEY AND HD.OWKEY = DT.OWKEY AND HD.RB_OBHDKEY = DT.OBHDKEY AND DT.ORDSEPTYPECD = '30' GROUP BY DT.CTKEY , DT.OWKEY , DT.ICKEY , HD.RB_BOXNM ), RB_HD_MATCH AS ( /* [2단계] 품목 우선순위별로, 그 품목을 포함한 헤더-규격 조합 매핑 */ SELECT HD.CTKEY , HD.OWKEY , HD.RB_OBHDKEY , HD.RB_BOXNM , IR.ICKEY , IR.ITEM_RK FROM RB_OB_INFO HD INNER JOIN OB_BASE DT ON HD.CTKEY = DT.CTKEY AND HD.OWKEY = DT.OWKEY AND HD.RB_OBHDKEY = DT.OBHDKEY AND DT.ORDSEPTYPECD = '30' INNER JOIN RB_ITEM_RANK IR ON DT.CTKEY = IR.CTKEY AND DT.OWKEY = IR.OWKEY AND DT.ICKEY = IR.ICKEY AND HD.RB_BOXNM = IR.RB_BOXNM ), RB_OB_RANK AS ( /* [3단계] 규격별로, 품목 우선순위를 기준으로 헤더 순위를 매김 */ SELECT OBINFO.CTKEY , OBINFO.OWKEY , OBINFO.RB_OBHDKEY , OBINFO.RB_BOXNM , OBINFO.CBM , OBINFO.WEIGHT , OBINFO.MAXLEN , OBINFO.SKU , OBINFO.PCS , OBINFO.OBDT_CNT , OB.RK FROM ( SELECT CTKEY , OWKEY , RB_OBHDKEY , RB_BOXNM , MIN(ITEM_RK) AS BEST_ITEM_RK -- 헤더가 가진 품목 중 가장 높은 우선순위 , ROW_NUMBER() OVER(PARTITION BY RB_BOXNM ORDER BY MIN(ITEM_RK)) AS RK FROM RB_HD_MATCH GROUP BY CTKEY, OWKEY, RB_BOXNM, RB_OBHDKEY ) OB INNER JOIN RB_OB_INFO OBINFO ON OB.CTKEY = OBINFO.CTKEY AND OB.OWKEY = OBINFO.OWKEY AND OB.RB_OBHDKEY = OBINFO.RB_OBHDKEY AND OB.RB_BOXNM = OBINFO.RB_BOXNM LEFT OUTER JOIN OB_BASE DT ON OB.CTKEY = DT.CTKEY AND OB.OWKEY = DT.OWKEY AND OB.RB_OBHDKEY = DT.OBHDKEY AND DT.ORDSEPTYPECD = '30' GROUP BY OBINFO.CTKEY , OBINFO.OWKEY , OBINFO.RB_OBHDKEY , OBINFO.RB_BOXNM , OBINFO.CBM , OBINFO.WEIGHT , OBINFO.MAXLEN , OBINFO.SKU , OBINFO.PCS , OBINFO.OBDT_CNT , OB.RK ), OB_RB AS ( SELECT OB.CTKEY , OB.OWKEY , OB.RB_OBHDKEY , OB.RB_BOXNM , OB.CBM , OB.WEIGHT , DT.RECOMBOXBARCODE , OB.MAXLEN , OB.SKU , OB.PCS AS RB_PCS , OB.OBDT_CNT , OB.RK FROM ( SELECT CTKEY , OWKEY , RB_OBHDKEY , RB_BOXNM , CBM , WEIGHT , MAXLEN , SKU , PCS , OBDT_CNT , RK
FROM RB_OB_INFO
FROM RB_OB_RANK
WHERE 1=1
(RB_BOXNM = #{item.boxnm} AND RK <= #{item.noCellSet})
) OB LEFT OUTER JOIN OB_BASE DT ON OB.CTKEY = DT.CTKEY AND OB.OWKEY = DT.OWKEY AND OB.RB_OBHDKEY = DT.OBHDKEY AND DT.ORDSEPTYPECD = '30' GROUP BY OB.CTKEY , OB.OWKEY , OB.RB_OBHDKEY , OB.RB_BOXNM , OB.CBM , OB.WEIGHT , DT.RECOMBOXBARCODE , OB.MAXLEN , OB.SKU , OB.PCS , OB.OBDT_CNT , OB.RK ), MX_OB_INFO AS ( SELECT A.* , ROW_NUMBER() OVER(PARTITION BY MX_BOXNM ORDER BY MX_BOXNM, MX_OBHDKEY ASC) AS RK FROM ( SELECT CTKEY , OWKEY , OBHDKEY AS MX_OBHDKEY /*릴리즈코드*/ , BOXNM AS MX_BOXNM , CBM , WEIGHT , COUNT(ICKEY) AS SKU , SUM(EXPCTQTY) AS PCS , MAX(MAXLEN) AS MAXLEN , ROUND(COUNT(CASE WHEN ROBSORTERICYN = 'Y' THEN 1 END) * 100 / COUNT(*), 0) AS RBRATIO , SUM(CASE WHEN ROBSORTERICYN = 'N' THEN EXPCTQTY ELSE 0 END) AS FBPCS , COUNT(OBDTKEY) AS OBDT_CNT FROM OB_BASE WHERE ORDSEPTYPECD = '40' GROUP BY CTKEY , OWKEY , OBHDKEY /*릴리즈코드*/ , BOXNM , CBM , WEIGHT ) A WHERE 1=1
), MX_ITEM_RANK AS ( /* [1단계] 품목코드별 등장 건수 순위 */ SELECT DT.CTKEY , DT.OWKEY , DT.ICKEY , HD.MX_BOXNM , COUNT(DISTINCT DT.OBHDKEY) AS OBHD_CNT , ROW_NUMBER() OVER(PARTITION BY HD.MX_BOXNM ORDER BY COUNT(DISTINCT DT.OBHDKEY) DESC) AS ITEM_RK FROM MX_OB_INFO HD INNER JOIN OB_BASE DT ON HD.CTKEY = DT.CTKEY AND HD.OWKEY = DT.OWKEY AND HD.MX_OBHDKEY = DT.OBHDKEY AND DT.ORDSEPTYPECD = '40' GROUP BY DT.CTKEY , DT.OWKEY , DT.ICKEY , HD.MX_BOXNM ), MX_HD_MATCH AS ( /* [2단계] 품목 우선순위별로, 그 품목을 포함한 헤더-규격 조합 매핑 */ SELECT HD.CTKEY , HD.OWKEY , HD.MX_OBHDKEY , HD.MX_BOXNM , IR.ICKEY , IR.ITEM_RK FROM MX_OB_INFO HD INNER JOIN OB_BASE DT ON HD.CTKEY = DT.CTKEY AND HD.OWKEY = DT.OWKEY AND HD.MX_OBHDKEY = DT.OBHDKEY AND DT.ORDSEPTYPECD = '40' INNER JOIN MX_ITEM_RANK IR ON DT.CTKEY = IR.CTKEY AND DT.OWKEY = IR.OWKEY AND DT.ICKEY = IR.ICKEY AND HD.MX_BOXNM = IR.MX_BOXNM ), MX_OB_RANK AS ( /* [3단계] 규격별로, 품목 우선순위를 기준으로 헤더 순위를 매김 */ SELECT OBINFO.CTKEY , OBINFO.OWKEY , OBINFO.MX_OBHDKEY , OBINFO.MX_BOXNM , OBINFO.CBM , OBINFO.WEIGHT , DT.RECOMBOXBARCODE , OBINFO.MAXLEN , OBINFO.SKU , OBINFO.PCS , OBINFO.OBDT_CNT , OB.RK FROM ( SELECT CTKEY , OWKEY , MX_OBHDKEY , MX_BOXNM , MIN(ITEM_RK) AS BEST_ITEM_RK -- 헤더가 가진 품목 중 가장 높은 우선순위 , ROW_NUMBER() OVER(PARTITION BY MX_BOXNM ORDER BY MIN(ITEM_RK)) AS RK FROM MX_HD_MATCH GROUP BY CTKEY, OWKEY, MX_BOXNM, MX_OBHDKEY ) OB INNER JOIN MX_OB_INFO OBINFO ON OB.CTKEY = OBINFO.CTKEY AND OB.OWKEY = OBINFO.OWKEY AND OB.MX_OBHDKEY = OBINFO.MX_OBHDKEY AND OB.MX_BOXNM = OBINFO.MX_BOXNM LEFT OUTER JOIN OB_BASE DT ON OB.CTKEY = DT.CTKEY AND OB.OWKEY = DT.OWKEY AND OB.MX_OBHDKEY = DT.OBHDKEY AND DT.ORDSEPTYPECD = '40' GROUP BY OBINFO.CTKEY , OBINFO.OWKEY , OBINFO.MX_OBHDKEY , OBINFO.MX_BOXNM , OBINFO.CBM , OBINFO.WEIGHT , DT.RECOMBOXBARCODE , OBINFO.MAXLEN , OBINFO.SKU , OBINFO.PCS , OBINFO.OBDT_CNT , OB.RK ), OB_MX AS ( SELECT OB.CTKEY , OB.OWKEY , OB.MX_OBHDKEY , OB.MX_BOXNM , OB.CBM , OB.WEIGHT , DT.RECOMBOXBARCODE , OB.MAXLEN , OB.SKU , SUM(DT.EXPCTQTY) AS MX_PCS , OB.OBDT_CNT , OB.RK FROM ( SELECT CTKEY , OWKEY , MX_OBHDKEY , MX_BOXNM , CBM , WEIGHT , MAXLEN , SKU , PCS , OBDT_CNT , RK
FROM MX_OB_INFO
FROM MX_OB_RANK
WHERE 1=1
(MX_BOXNM = #{item.boxnm} AND RK <= #{item.fbCellSet})
) OB LEFT OUTER JOIN OB_BASE DT ON OB.CTKEY = DT.CTKEY AND OB.OWKEY = DT.OWKEY AND OB.MX_OBHDKEY = DT.OBHDKEY AND DT.ORDSEPTYPECD = '40' GROUP BY OB.CTKEY , OB.OWKEY , OB.MX_OBHDKEY , OB.MX_BOXNM , OB.CBM , OB.WEIGHT , DT.RECOMBOXBARCODE , OB.MAXLEN , OB.SKU , OB.OBDT_CNT , OB.RK ), OB_MX_RB AS ( SELECT MX.CTKEY , MX.OWKEY , MX.MX_OBHDKEY AS MX_RB_OBHDKEY , MX.MX_BOXNM , MX.CBM , MX.WEIGHT , OB.RECOMBOXBARCODE , MX.MAXLEN , MX.SKU , SUM(OB.EXPCTQTY) AS MX_RB_PCS , MX.OBDT_CNT , MX.RK FROM OB_MX MX INNER JOIN OB_BASE OB ON MX.CTKEY = OB.CTKEY AND MX.OWKEY = OB.OWKEY AND MX.MX_OBHDKEY = OB.OBHDKEY AND OB.ORDSEPTYPECD = '40' AND OB.ROBSORTERICYN = 'Y' GROUP BY MX.CTKEY , MX.OWKEY , MX.MX_OBHDKEY , MX.MX_BOXNM , MX.CBM , MX.WEIGHT , OB.RECOMBOXBARCODE , MX.MAXLEN , MX.SKU , MX.OBDT_CNT , MX.RK ), OB_MX_FB AS ( SELECT MX.CTKEY , MX.OWKEY , MX.MX_OBHDKEY AS MX_FB_OBHDKEY , MX.MX_BOXNM , MX.CBM , MX.WEIGHT , OB.RECOMBOXBARCODE , MX.MAXLEN , MX.SKU , SUM(OB.EXPCTQTY) AS MX_FB_PCS , MX.OBDT_CNT , MX.RK FROM OB_MX MX INNER JOIN OB_BASE OB ON MX.CTKEY = OB.CTKEY AND MX.OWKEY = OB.OWKEY AND MX.MX_OBHDKEY = OB.OBHDKEY AND OB.ORDSEPTYPECD = '40' AND OB.ROBSORTERICYN = 'N' GROUP BY MX.CTKEY , MX.OWKEY , MX.MX_OBHDKEY , MX.MX_BOXNM , MX.CBM , MX.WEIGHT , OB.RECOMBOXBARCODE , MX.MAXLEN , MX.SKU , MX.OBDT_CNT , MX.RK ), RB_SKU AS ( SELECT RB.CTKEY , RB.OWKEY , RB.RB_BOXNM , COUNT(DISTINCT ICKEY) AS RSLT_RB_SKU FROM OB_RB RB INNER JOIN OB_BASE OB ON RB.CTKEY = OB.CTKEY AND RB.OWKEY = OB.OWKEY AND RB.RB_OBHDKEY = OB.OBHDKEY AND RB.RB_BOXNM = OB.BOXNM AND OB.ORDSEPTYPECD = '30' GROUP BY RB.CTKEY , RB.OWKEY , RB.RB_BOXNM ), MX_SKU AS ( SELECT MX.CTKEY , MX.OWKEY , MX.MX_BOXNM , COUNT(DISTINCT ICKEY) AS RSLT_MX_SKU FROM OB_MX MX INNER JOIN OB_BASE OB ON MX.CTKEY = OB.CTKEY AND MX.OWKEY = OB.OWKEY AND MX.MX_OBHDKEY = OB.OBHDKEY AND MX.MX_BOXNM = OB.BOXNM AND OB.ORDSEPTYPECD = '40' GROUP BY MX.CTKEY , MX.OWKEY , MX.MX_BOXNM ), MX_RB_SKU AS ( SELECT MXRB.CTKEY , MXRB.OWKEY , MXRB.MX_BOXNM , COUNT(DISTINCT ICKEY) AS RSLT_MX_RB_SKU FROM OB_MX_RB MXRB INNER JOIN OB_BASE OB ON MXRB.CTKEY = OB.CTKEY AND MXRB.OWKEY = OB.OWKEY AND MXRB.MX_RB_OBHDKEY = OB.OBHDKEY AND MXRB.MX_BOXNM = OB.BOXNM AND OB.ORDSEPTYPECD = '40' AND OB.ROBSORTERICYN = 'Y' GROUP BY MXRB.CTKEY , MXRB.OWKEY , MXRB.MX_BOXNM ), MX_FB_SKU AS ( SELECT MXFB.CTKEY , MXFB.OWKEY , MXFB.MX_BOXNM , COUNT(DISTINCT ICKEY) AS RSLT_MX_FB_SKU FROM OB_MX_FB MXFB INNER JOIN OB_BASE OB ON MXFB.CTKEY = OB.CTKEY AND MXFB.OWKEY = OB.OWKEY AND MXFB.MX_FB_OBHDKEY = OB.OBHDKEY AND MXFB.MX_BOXNM = OB.BOXNM AND OB.ORDSEPTYPECD = '40' AND ROBSORTERICYN = 'N' GROUP BY MXFB.CTKEY , MXFB.OWKEY , MXFB.MX_BOXNM )

mapper.update:
/* wms-outbound-obWaveMgmt-sql-oracle.xml - updateObWaveDlvrySbm - WMS > 출고 관리 > 웨이브관리 > 웨이브 헤더 택배사 업데이트 */
UPDATE TWORK_INFO_WA_HD
   SET DLVRYCORPCD = #{dlvryCorpCd}
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND WAHDKEY = #{wahdkey}

/* wms-outbound-obWaveMgmt-sql-oracle.xml - updateObWaveMgmtWkClassWaHd - WMS > 출고 관리 > 웨이브관리 > 분류계획전송 - 웨이브 헤더 실패 상태값 변경 */
UPDATE TWORK_INFO_WA_HD
   SET WAWKSTATUSCD = #{wawkstatuscd}
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND WAHDKEY = #{wahdkey}

mapper.sql:
/* wms-outbound-obWaveMgmt-sql-oracle.xml - selectWaveMgmtPopInfoRefSql -WMS > 출고 관리 > 웨이브관리 > 웨이브 정보 상세 SQL */ FROM TWORK_INFO_WA_HD WA INNER JOIN TWORK_INFO_WA_DT WD ON WA.CTKEY = WD.CTKEY AND WA.OWKEY = WD.OWKEY AND WA.WAHDKEY = WD.WAHDKEY INNER JOIN TWORK_INFO_OB_HD OH ON WD.CTKEY = OH.CTKEY AND WD.OWKEY = OH.OWKEY AND WD.OBHDKEY = OH.OBHDKEY INNER JOIN TWORK_INFO_OB_DT OD ON OH.CTKEY = OD.CTKEY AND OH.OWKEY = OD.OWKEY AND OH.OBHDKEY = OD.OBHDKEY INNER JOIN TWORK_MST_IC IC ON OD.CTKEY = IC.CTKEY AND OD.OWKEY = IC.OWKEY AND OD.ICKEY = IC.ICKEY
LEFT OUTER JOIN TWORK_MST_BOX BOX ON WD.CTKEY = BOX.CTKEY AND WD.RECOMBOXBARCODE = BOX.BOXBARCODE
LEFT OUTER JOIN TWORK_MST_DLVRYCORP DLV ON WA.CTKEY = DLV.CTKEY AND WA.OWKEY = DLV.OWKEY AND WA.DLVRYCORPCD = DLV.DLVRYCORPCD AND DLV.DELYN = 'N' AND TO_CHAR(CURRENT_TIMESTAMP, 'YYYYMMDD') BETWEEN CNTRCTSTARTDAY AND CNTRCTCLOSEDAY LEFT OUTER JOIN TWORK_INFO_HANJIN_SBM HJSBM /*한진택배 접수정보*/ ON OH.CTKEY = HJSBM.CTKEY AND OH.OWKEY = HJSBM.OWKEY AND OH.OBHDKEY = HJSBM.OBHDKEY AND OH.WBLNO = HJSBM.WBLNO
LEFT OUTER JOIN ( SELECT DISTINCT IN_OH.CTKEY , IN_OH.OWKEY , IN_OH.OBHDKEY FROM TWORK_INFO_OB_HD IN_OH INNER JOIN TWORK_INFO_WBL_PRHS PR ON IN_OH.CTKEY = PR.CTKEY AND IN_OH.OWKEY = PR.OWKEY AND IN_OH.OBHDKEY = PR.OBHDKEY AND IN_OH.WBLNO = PR.WBLNO WHERE IN_OH.CTKEY = #{ctkey} AND IN_OH.OWKEY = #{owkey} AND IN_OH.WAHDKEY = #{wahdkey} ) WBL ON OH.CTKEY = WBL.CTKEY AND OH.OWKEY = WBL.OWKEY AND OH.OBHDKEY = WBL.OBHDKEY
WHERE WA.CTKEY = #{ctkey} AND WA.OWKEY = #{owkey} AND WA.WAHDKEY = #{wahdkey}
AND WD.DELYN = 'N'
AND OH.OBHDDAY BETWEEN #{obhddayfr} AND #{obhddayto}
AND OH.OBSTATUSCD IN
#{obstatuscd}
AND OD.OBDTSTATUSCD IN
#{obstatuscd}
AND OH.DLVRYPRGRSTATUSCD = #{dlvrystatus}
AND (CASE WHEN WBL.OBHDKEY IS NOT NULL THEN 'Y' ELSE 'N' END) = #{wblpryn}
AND OH.WBLNO LIKE ('%' || #{edtcondsch} || '%')
AND OH.OBHDKEY LIKE ('%' || #{edtcondsch} || '%')
AND OH.OBORDKEY LIKE ('%' || #{edtcondsch} || '%')
AND OH.EXTERNORDERKEY LIKE ('%' || #{edtcondsch} || '%')
AND OH.ORHDKEY LIKE ('%' || #{edtcondsch} || '%')
AND OH.RCPPRSNNM LIKE ('%' || #{edtcondsch} || '%')
AND OH.ORDNM LIKE ('%' || #{edtcondsch} || '%')
AND OH.RCPPRSNTELNO LIKE ('%' || #{edtcondsch} || '%')
AND OH.RCPPRSNTELNO2 LIKE ('%' || #{edtcondsch} || '%')
AND OH.RCPPRSNADDR1 LIKE ('%' || #{edtcondsch} || '%')
AND OH.CMT LIKE ('%' || #{edtcondsch} || '%')
AND OD.ICKEY IN
#{ickey}
AND WD.DELYN = #{exclusion}

mapper.select:
/* wms-outbound-obWaveMgmt-sql-oracle.xml - selectWaveMgmtPopInfo_T01_Add - WMS > 출고 관리 > 웨이브관리 > 웨이브 정보 상세 > 출고 계획 > 추가 - 출고주문 조회 */ SELECT 0 AS CHK , OH.CTKEY , OH.OWKEY , OH.OBORDKEY , OH.OBHDKEY , OH.OBHDDAY , OH.OBSTATUSCD , OH.CLASSIFSPECCD , OH.RECOMBOXBARCODE
, (CASE WHEN BOX.BOXDIVCD = '10' THEN BOX.BOXNM ELSE '그외' END) AS BOXNM
, BOX.BOXNM
, OH.CBM , (OH.WEIGHT / 1000) AS WEIGHT , COUNT(DISTINCT OD.ICKEY) AS SKU , SUM(OD.INITQTY) AS PCS , #{wahdkey} AS WAHDKEY , #{wktypecd} AS WKTYPECD , #{oriobhdkey} AS ORIOBHDKEY , #{stnbarcode} AS STNBARCODE , #{oriboxnm} AS ORIBOXNM FROM TWORK_INFO_OB_HD OH INNER JOIN TWORK_INFO_OB_DT OD ON OH.CTKEY = OD.CTKEY AND OH.OWKEY = OD.OWKEY AND OH.OBHDKEY = OD.OBHDKEY INNER JOIN TWORK_MST_BOX BOX ON OH.CTKEY = BOX.CTKEY AND OH.RECOMBOXBARCODE = BOX.BOXBARCODE WHERE OH.CTKEY = #{ctkey} AND OH.OWKEY = #{owkey} AND OH.WKTYPECD = #{wktypecd} AND OH.OBHDDAY BETWEEN #{obhddayfr} AND #{obhddayto}
AND OH.OBHDKEY = #{obhdkey}
AND OH.OBSTATUSCD = '00' AND OH.OBHDTYPECD IN ('10','20') AND OH.WAHDKEY IS NULL
AND OH.CLASSIFSPECCD = #{classifspeccd}
AND (CASE WHEN BOX.BOXDIVCD = '10' THEN BOX.BOXNM ELSE '그외' END) = #{oriboxnm}
GROUP BY OH.CTKEY , OH.OWKEY , OH.OBORDKEY , OH.OBHDKEY , OH.OBHDDAY , OH.OBSTATUSCD , OH.CLASSIFSPECCD , OH.RECOMBOXBARCODE , OH.CBM , OH.WEIGHT
, (CASE WHEN BOX.BOXDIVCD = '10' THEN BOX.BOXNM ELSE '그외' END)
, BOX.BOXNM

/* wms-outbound-obWaveMgmt-sql-oracle.xml - selectwaveMgmtPopInfo_T01_Add_WaAddWastatus - WMS > 출고 관리 > 웨이브관리 > 웨이브 정보 상세 > 출고 계획 > 추가 - 웨이브 처리가능 상태 확인 */
SELECT CTKEY
	 , OWKEY
	 , WAHDKEY
	 , WAWKSTATUSCD
  FROM TWORK_INFO_WA_HD
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND WAHDKEY = #{wahdkey}
   AND WAWKSTATUSCD IN ('05','10','11','15','20')

/* wms-outbound-obWaveMgmtManager-sql-oracle.xml - selectWaveMgmtUpdateWarnd - WMS > 출고 관리 > 웨이브관리 > 수정 - 회차 조회 */
SELECT COALESCE(MAX(TO_NUMBER(COALESCE(WARND, 0))), 0) + 1 AS WARND
  FROM TWORK_INFO_WA_HD
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND WAHDDAY = #{wahdday}

mapper.update:
/* wms-outbound-obWaveMgmt-sql-oracle.xml - updateWaveMgmtUpdate - WMS > 출고 관리 > 웨이브관리 > 수정 - 웨이브 헤더 업데이트 */
UPDATE TWORK_INFO_WA_HD
   SET WAHDDAY = #{wahdday}
	 , WARND = #{warnd}
   	 , WAHDNM = #{wahdnm}
   	 , CMT = #{cmt}
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND WAHDKEY = #{wahdkey}

mapper.select:
/* wms-outbound-obWaveMgmt-sql-oracle.xml - selectWaHdRngChg - WMS > 출고 관리 > 웨이브관리 > 회차변경 - 변경가능상태 체크 */
SELECT CTKEY
	 , OWKEY
	 , #{wahdkey} AS ORIWAHDKEY
	 , WAWKSTATUSCD
	 , WKTYPECD
  FROM TWORK_INFO_WA_HD
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND WAHDKEY = #{wahdkey}
   AND WAWKSTATUSCD IN ('05','10','15','20','25','30','99')
   AND WKTYPECD = 'DW'

/* wms-outbound-obWaveMgmt-sql-oracle.xml - selectWaveMgmtPopTaskList_T01 - WMS > 출고 관리 > 웨이브관리 > 작업현황 - 주문별 작업 현황 조회 */ SELECT 0 AS CHK , WA.CTKEY /*센터코드*/ , WA.OWKEY /*화주코드*/ , WA.WAHDKEY /*웨이브코드*/ , WA.PIHDKEY /*피킹헤더코드*/ , WD.OBHDKEY /*릴리즈코드*/ , WA.WKTYPECD /*작업유형*/ , OH.ORDSEPTYPECD /*주문분리유형*/ , OH.OBSTATUSCD /*출고상태*/ , COUNT(OD.ICKEY) AS SKU /*SKU*/ , SUM(OD.EXPCTQTY) AS PCS /*PCS*/ , SUM(OD.PKQTY) AS PKQTY /*피킹수량*/ , SUM(OD.PAKQTY) AS PAKQTY /*패킹수량*/ , (CASE WHEN NIS.OBHDKEY IS NOT NULL THEN 'O' ELSE 'X' END) AS NISYN /*결품_보류여부*/ , (CASE WHEN COALESCE(NIS.CNFRMYN, 'N') = 'N' THEN 'X' ELSE 'O' END) AS CNFRMYN /*결품_처리여부*/ , SUM(OD.CNFRMQTY) AS CNFRMQTY /*확정수량*/ FROM TWORK_INFO_WA_HD WA INNER JOIN TWORK_INFO_WA_DT WD ON WA.CTKEY = WD.CTKEY AND WA.OWKEY = WD.OWKEY AND WA.WAHDKEY = WD.WAHDKEY AND WD.DELYN = 'N' INNER JOIN TWORK_INFO_OB_HD OH ON WD.CTKEY = OH.CTKEY AND WD.OWKEY = OH.OWKEY AND WD.OBHDKEY = OH.OBHDKEY INNER JOIN TWORK_INFO_OB_DT OD ON OH.CTKEY = OD.CTKEY AND OH.OWKEY = OD.OWKEY AND OH.OBHDKEY = OD.OBHDKEY LEFT OUTER JOIN TWORK_INFO_OB_NIS_HD NIS ON OH.CTKEY = NIS.CTKEY AND OH.OWKEY = NIS.OWKEY AND OH.OBHDKEY = NIS.OBHDKEY WHERE WA.CTKEY = #{ctkey} AND WA.OWKEY = #{owkey} AND WA.PIHDKEY = #{pihdkey}
AND WA.WKTYPECD = #{wktypecd}
AND OH.ORDSEPTYPECD = #{ordseptypecd}
AND NIS.OBHDKEY IS NOT NULL
AND NIS.OBHDKEY IS NULL
GROUP BY WA.CTKEY /*센터코드*/ , WA.OWKEY /*화주코드*/ , WA.WAHDKEY /*웨이브코드*/ , WA.PIHDKEY /*피킹헤더코드*/ , WD.OBHDKEY /*릴리즈코드*/ , WA.WKTYPECD /*작업유형*/ , OH.ORDSEPTYPECD /*주문분리유형*/ , OH.OBSTATUSCD /*출고상태*/ , NIS.OBHDKEY /*결품_보류여부*/ , NIS.CNFRMYN /*결품_처리여부*/ ORDER BY WD.OBHDKEY

/* wms-outbound-obWaveMgmt-sql-oracle.xml - selectWaveMgmtPopTaskList_T02 - WMS > 출고 관리 > 웨이브관리 > 작업현황 - 상품별 작업 현황 조회 */ SELECT WA.CTKEY /*센터코드*/ , WA.OWKEY /*화주코드*/ , WA.PIHDKEY /*피킹헤더코드*/ , WA.WKTYPECD /*작업유형*/ , OD.ICKEY /*상품코드*/ , IC.ICNM /*상품명*/ , SUM(OD.EXPCTQTY) AS EXPCTQTY /*예정수량*/ , SUM(OD.PKQTY) AS PKQTY /*피킹수량*/ , SUM(OD.PAKQTY) AS PAKQTY /*패킹수량*/ , SUM(OD.CNFRMQTY) AS CNFRMQTY /*확정수량*/ FROM TWORK_INFO_WA_HD WA INNER JOIN TWORK_INFO_WA_DT WD ON WA.CTKEY = WD.CTKEY AND WA.OWKEY = WD.OWKEY AND WA.WAHDKEY = WD.WAHDKEY AND WD.DELYN = 'N' INNER JOIN TWORK_INFO_OB_HD OH ON WD.CTKEY = OH.CTKEY AND WD.OWKEY = OH.OWKEY AND WD.OBHDKEY = OH.OBHDKEY INNER JOIN TWORK_INFO_OB_DT OD ON OH.CTKEY = OD.CTKEY AND OH.OWKEY = OD.OWKEY AND OH.OBHDKEY = OD.OBHDKEY INNER JOIN TWORK_MST_IC IC ON OD.CTKEY = IC.CTKEY AND OD.OWKEY = IC.OWKEY AND OD.ICKEY = IC.ICKEY WHERE WA.CTKEY = #{ctkey} AND WA.OWKEY = #{owkey} AND WA.PIHDKEY = #{pihdkey}
AND WA.WKTYPECD = #{wktypecd}
GROUP BY WA.CTKEY /*센터코드*/ , WA.OWKEY /*화주코드*/ , WA.PIHDKEY /*피킹헤더코드*/ , WA.WKTYPECD /*작업유형*/ , OD.ICKEY /*상품코드*/ , IC.ICNM /*상품명*/ ORDER BY OD.ICKEY

/* wms-outbound-obWaveMgmt-sql-oracle.xml - selectWaveMgmtPopTaskList_T03 - WMS > 출고 관리 > 웨이브관리 > 작업현황 - 피킹리스트 조회 */ SELECT OB.CTKEY /*센터코드*/ , OB.OWKEY /*화주코드*/ , OB.PIHDKEY /*피킹헤더코드*/ , OB.ZNNM /*존*/ , OB.ARNM /*구역명*/ , OB.LCKEY /*로케이션*/ , OB.ICKEY /*상품코드*/ , OB.ICNM /*상품명*/ , OB.BARCODE /*바코드*/ , OB.EXPDATE /*유통기한*/ , COALESCE(OB.QTY_EXP, 0) AS QTY_EXP , TRUNC( (CASE WHEN COALESCE(SUM(COALESCE(OB.QTY_EXP, 0)), 0) > 0 AND COALESCE(OB.ICUNITQTY_INN, 0) > 0 THEN COALESCE(SUM(COALESCE(OB.QTY_EXP, 0)), 0) / COALESCE(OB.ICUNITQTY_INN, 0) ELSE 0 END), 1) AS QTY_INN , TRUNC( (CASE WHEN COALESCE(SUM(COALESCE(OB.QTY_EXP, 0)), 0) > 0 AND COALESCE(OB.ICUNITQTY_CTN, 0) > 0 THEN COALESCE(SUM(COALESCE(OB.QTY_EXP, 0)), 0) / COALESCE(OB.ICUNITQTY_CTN, 0) ELSE 0 END), 1) AS QTY_CTN , COALESCE(SUM(COALESCE(PT.EXPCTQTY, 0)), 0) AS QTY_TOT_EXP , COALESCE(SUM(COALESCE(PT.CNFRMQTY, 0)), 0) AS QTY_TOT_CNFRM , COALESCE(OB.ICUNITQTY_INN, 0) AS ICUNITQTY_INN , COALESCE(OB.ICUNITQTY_CTN, 0) AS ICUNITQTY_CTN , COALESCE(PT.ROBSORTERICYN, 'N') AS ROBSORTERICYN , PT.IVATKEY FROM ( SELECT WA.CTKEY /*센터코드*/ , WA.OWKEY /*화주코드*/ , WA.PIHDKEY /*피킹헤더코드*/ , ZN.ZNNM /*존*/ , AR.ARNM /*구역명*/ , PD.LCKEY /*로케이션*/ , OD.ICKEY /*상품코드*/ , IC.ICNM /*상품명*/ , BAR.BARCODE /*바코드*/ , IVAT.EXPDATE /*유통기한*/ , COALESCE(SUM(COALESCE(PD.EXPCTQTY, 0)), 0) AS QTY_EXP , COALESCE(INN.ICUNITQTY, 0) AS ICUNITQTY_INN , COALESCE(CTN.ICUNITQTY, 0) AS ICUNITQTY_CTN FROM TWORK_INFO_WA_HD WA INNER JOIN TWORK_INFO_WA_DT WD ON WA.CTKEY = WD.CTKEY AND WA.OWKEY = WD.OWKEY AND WA.WAHDKEY = WD.WAHDKEY AND WD.DELYN = 'N' INNER JOIN TWORK_INFO_OB_HD OH ON WD.CTKEY = OH.CTKEY AND WD.OWKEY = OH.OWKEY AND WD.OBHDKEY = OH.OBHDKEY INNER JOIN TWORK_INFO_OB_DT OD ON OH.CTKEY = OD.CTKEY AND OH.OWKEY = OD.OWKEY AND OH.OBHDKEY = OD.OBHDKEY INNER JOIN TWORK_INFO_PI_DT PD ON OD.CTKEY = PD.CTKEY AND OD.OWKEY = PD.OWKEY AND OD.OBHDKEY = PD.OBHDKEY AND OD.OBDTKEY = PD.OBDTKEY INNER JOIN TWORK_INFO_IVAT IVAT ON PD.CTKEY = IVAT.CTKEY AND PD.OWKEY = IVAT.OWKEY AND PD.ICKEY = IVAT.ICKEY AND PD.IVATKEY = IVAT.IVATKEY INNER JOIN TWORK_MST_IC IC ON PD.CTKEY = IC.CTKEY AND PD.OWKEY = IC.OWKEY AND PD.ICKEY = IC.ICKEY LEFT OUTER JOIN TWORK_MST_ICUTXTYPE INN ON PD.CTKEY = INN.CTKEY AND PD.OWKEY = INN.OWKEY AND PD.ICUNITKEY = INN.ICUNITKEY AND PD.ICKEY = INN.ICKEY AND INN.ICUNITTYPECD = 'INN' LEFT OUTER JOIN TWORK_MST_ICUTXTYPE CTN ON PD.CTKEY = CTN.CTKEY AND PD.OWKEY = CTN.OWKEY AND PD.ICUNITKEY = CTN.ICUNITKEY AND PD.ICKEY = CTN.ICKEY AND CTN.ICUNITTYPECD = 'CTN' INNER JOIN TWORK_MST_LC LC ON PD.CTKEY = LC.CTKEY AND PD.LCKEY = LC.LCKEY INNER JOIN TWORK_MST_AR AR ON LC.CTKEY = AR.CTKEY AND LC.ARKEY = AR.ARKEY INNER JOIN TWORK_MST_ZN ZN ON AR.CTKEY = ZN.CTKEY AND AR.ZNKEY = ZN.ZNKEY LEFT OUTER JOIN TWORK_MST_ICBARCODE BAR ON IC.CTKEY = BAR.CTKEY AND IC.OWKEY = BAR.OWKEY AND IC.ICKEY = BAR.ICKEY AND OD.UOM = BAR.UOM WHERE WA.CTKEY = #{ctkey} AND WA.OWKEY = #{owkey} AND WA.PIHDKEY = #{pihdkey}
AND WA.WKTYPECD = #{wktypecd}
GROUP BY WA.CTKEY /*센터코드*/ , WA.OWKEY /*화주코드*/ , WA.PIHDKEY /*피킹헤더코드*/ , ZN.ZNNM /*존*/ , AR.ARNM /*구역명*/ , PD.LCKEY /*로케이션*/ , OD.ICKEY /*상품코드*/ , IC.ICNM /*상품명*/ , BAR.BARCODE /*바코드*/ , IVAT.EXPDATE /*유통기한*/ , INN.ICUNITQTY , CTN.ICUNITQTY ) OB INNER JOIN TWORK_INFO_PI_TOT_DT PT ON OB.CTKEY = PT.CTKEY AND OB.OWKEY = PT.OWKEY AND OB.PIHDKEY = PT.PIHDKEY AND OB.ICKEY = PT.ICKEY AND OB.LCKEY = PT.LCKEY GROUP BY OB.CTKEY /*센터코드*/ , OB.OWKEY /*화주코드*/ , OB.PIHDKEY /*피킹헤더코드*/ , OB.ZNNM /*존*/ , OB.ARNM /*구역명*/ , OB.LCKEY /*로케이션*/ , OB.ICKEY /*상품코드*/ , OB.ICNM /*상품명*/ , OB.BARCODE /*바코드*/ , OB.EXPDATE /*유통기한*/ , (OB.QTY_EXP,0) , COALESCE(OB.ICUNITQTY_INN, 0) , COALESCE(OB.ICUNITQTY_CTN, 0) , COALESCE(PT.ROBSORTERICYN, 'N') , PT.IVATKEY ORDER BY OB.ZNNM /*존*/ , OB.ARNM /*구역명*/ , OB.ICNM /*상품코드*/ , OB.EXPDATE /*유통기한*/

/* wms-outbound-obWaveMgmt-sql-oracle.xml - selectObWaveMgmtPkIstOmsDlvList - WMS > 출고 관리 > 웨이브관리 > 작업지시 > OMS로 보내는 출고상태 리스트 */
SELECT WH.CTKEY
	 , WH.OWKEY
	 , OH.OBHDKEY
	 , OH.OBORDKEY
  FROM TWORK_INFO_WA_HD WH
 INNER JOIN TWORK_INFO_WA_DT WD
	ON WH.CTKEY = WD.CTKEY
   AND WH.OWKEY = WD.OWKEY
   AND WH.WAHDKEY = WD.WAHDKEY
 INNER JOIN TWORK_INFO_OB_HD OH
	ON WD.CTKEY = OH.CTKEY
   AND WD.OWKEY = OH.OWKEY
   AND WD.WAHDKEY = OH.WAHDKEY
   AND WD.OBHDKEY = OH.OBHDKEY
 WHERE




					(WH.CTKEY = #{item.ctkey}
				   AND WH.OWKEY = #{item.owkey}
				   AND WH.WAHDKEY = #{item.wahdkey}
				   AND WH.WKTYPECD NOT IN ('DW','RW'))




	   WH.CTKEY = #{ctkey}
   AND WH.OWKEY = #{owkey}
   AND WH.WAHDKEY = #{wahdkey}
   AND WH.WKTYPECD NOT IN ('DW','RW')


	   WH.CTKEY = #{ctkey}
   AND WH.OWKEY = #{owkey}
   AND WH.PIHDKEY = #{pihdkey}
   AND WH.WKTYPECD NOT IN ('DW','RW')


	   WH.CTKEY = #{ctkey}
   AND WH.OWKEY = #{owkey}
   AND WH.WAHDKEY = #{wahdkey}

/* wms-outbound-obWaveMgmt-sql-oracle.xml - selectObWaveCreteWaDtList - WMS > 출고 관리 > 웨이브관리 > 생성 > 저장 > 웨이브 상세 및 릴리즈 헤더 조회  */
SELECT WD.CTKEY
	 , WD.OWKEY
	 , WD.WAHDKEY
	 , WD.OBHDKEY
  FROM TWORK_INFO_WA_DT WD
 INNER JOIN TWORK_INFO_OB_HD OH
    ON WD.CTKEY = OH.CTKEY
   AND WD.OWKEY = OH.OWKEY
   AND WD.OBHDKEY = OH.OBHDKEY
 WHERE WD.CTKEY = #{ctkey}
   AND WD.OWKEY = #{owkey}
   AND WD.WAHDKEY = #{wahdkey}

/* wms-outbound-obWaveMgmt-sql-oracle.xml - selectObWaveMgmtPopCreateDasSkuObAss - WMS > 출고 관리 > 생성 > DAS 작업 계획 설정 > 주문 배정 주문건 조회(대,중,소)(SKU 집중화) 조회 */
SELECT CTKEY , OWKEY , OBORDKEY , OBHDKEY , CLASSIFSPECCD , RECOMBOXBARCODE , CBM AS VOL , WEIGHT , SKU AS TTICCNT , PCS AS TTICQTY , #{wahdkey} AS WAHDKEY , #{stnbarcode} AS DASSTNBARCODE FROM OB_RANK WHERE
CLASSIFSPECCD = #{spec}

/* wms-outbound-obWaveMgmt-sql-oracle.xml - selectObWaveMgmtPopCreateDasList - WMS > 출고 관리 > 웨이브관리 > 생성 > 저장 > 생성한 DAS 정보 조회 */ WITH STNLIST AS (
SELECT #{stn.ctkey} AS CTKEY, #{stn.owkey} AS OWKEY, #{stn.stnbarcode} AS STNBARCODE, #{stn.avcell} AS AVCELL, #{stn.cnt} AS CNT
) SELECT STN.CTKEY , STN.OWKEY , STN.STNBARCODE , STN.CLASSIFSPECCD , SUM(CASE CELL.CLASSIFSPECCD WHEN 'S' THEN 1 ELSE 0 END) AS S_CNT , SUM(CASE CELL.CLASSIFSPECCD WHEN 'M' THEN 1 ELSE 0 END) AS M_CNT , SUM(CASE CELL.CLASSIFSPECCD WHEN 'L' THEN 1 ELSE 0 END) AS L_CNT , LIST.AVCELL , LIST.CNT , 0 AS ALLOC_S_CNT , 0 AS ALLOC_M_CNT , 0 AS ALLOC_L_CNT FROM TWORK_INFO_WA_DAS_STN STN INNER JOIN TWORK_INFO_WA_DAS_CELL CELL ON STN.CTKEY = CELL.CTKEY AND STN.OWKEY = CELL.OWKEY AND STN.WAHDKEY = CELL.WAHDKEY AND STN.STNBARCODE = CELL.STNBARCODE INNER JOIN STNLIST LIST ON STN.CTKEY = LIST.CTKEY AND STN.STNBARCODE = LIST.STNBARCODE WHERE STN.CTKEY = #{ctkey} AND STN.OWKEY = #{owkey} AND STN.WAHDKEY = #{wahdkey} GROUP BY STN.CTKEY , STN.OWKEY , STN.STNBARCODE , STN.CLASSIFSPECCD , LIST.AVCELL , LIST.CNT ORDER BY STN.STNBARCODE

mapper.sql:
/* wms-outbound-obWaveMgmt-sql-oracle.xml - selectObWaveMgmtPopRbAssSql - WMS > 출고 관리 > 생성 > 로봇합포 작업 계획 설정 > 로봇합포 출고 대상 SQL */ WITH OB_BASE AS ( SELECT OH.CTKEY , OH.OWKEY , OH.OBORDKEY , OH.OBHDKEY , OH.CBM , (OH.WEIGHT / 1000) AS WEIGHT , OH.CLASSIFSPECCD , OH.RECOMBOXBARCODE , (CASE BOX.BOXDIVCD WHEN '10' THEN BOX.BOXNM ELSE '그외' END) BOXNM , OH.ORDSEPTYPECD , IC.ROBSORTERICYN , GREATEST(COALESCE(ICUTX.WIDTH, 0), COALESCE(ICUTX.DEPTH, 0), COALESCE(ICUTX.HEIGHT, 0)) AS MAXLEN , OD.OBDTKEY , OD.ICKEY , OD.EXPCTQTY FROM TWORK_INFO_OB_HD OH INNER JOIN TWORK_INFO_OB_DT OD ON OH.CTKEY = OD.CTKEY AND OH.OWKEY = OD.OWKEY AND OH.OBHDKEY = OD.OBHDKEY INNER JOIN TWORK_MST_IC IC ON OD.CTKEY = IC.CTKEY AND OD.OWKEY = IC.OWKEY AND OD.ICKEY = IC.ICKEY INNER JOIN TWORK_MST_ICUTXTYPE ICUTX ON OD.CTKEY = ICUTX.CTKEY AND OD.OWKEY = ICUTX.OWKEY AND OD.ICKEY = ICUTX.ICKEY AND OD.ICUNITKEY = ICUTX.ICUNITKEY AND OD.UOM = ICUTX.ICUNITTYPECD INNER JOIN TWORK_MST_BOX BOX ON OH.CTKEY = BOX.CTKEY AND OH.RECOMBOXBARCODE = BOX.BOXBARCODE WHERE OH.CTKEY = #{ctkey} AND OH.OWKEY = #{owkey} AND OH.WKTYPECD = 'RW' AND OH.WAHDKEY IS NULL AND OH.OBSTATUSCD = '00' AND OH.OBHDTYPECD IN ('10','20') AND OH.OBHDDAY BETWEEN #{obhddayfr} AND #{obhddayto} ), RB_OB_INFO AS ( SELECT A.* , ROW_NUMBER() OVER(PARTITION BY RB_BOXNM ORDER BY RB_BOXNM, RB_OBHDKEY ASC) AS RK FROM ( SELECT CTKEY , OWKEY , OBHDKEY AS RB_OBHDKEY /*릴리즈코드*/ , BOXNM AS RB_BOXNM , CBM , WEIGHT , COUNT(ICKEY) AS SKU , SUM(EXPCTQTY) AS PCS , MAX(MAXLEN) AS MAXLEN , ROUND(COUNT(CASE WHEN ROBSORTERICYN = 'Y' THEN 1 END) * 100 / COUNT(*), 0) AS RBRATIO , SUM(CASE WHEN ROBSORTERICYN = 'N' THEN EXPCTQTY ELSE 0 END) AS FBPCS , COUNT(OBDTKEY) AS OBDT_CNT FROM OB_BASE WHERE ORDSEPTYPECD = '30' GROUP BY CTKEY , OWKEY , OBHDKEY /*릴리즈코드*/ , BOXNM , CBM , WEIGHT ) A WHERE 1=1
), RB_ITEM_RANK AS ( /* [1단계] 품목코드별 등장 건수 순위 */ SELECT DT.CTKEY , DT.OWKEY , DT.ICKEY , HD.RB_BOXNM , COUNT(DISTINCT DT.OBHDKEY) AS OBHD_CNT , ROW_NUMBER() OVER(PARTITION BY HD.RB_BOXNM ORDER BY COUNT(DISTINCT DT.OBHDKEY) DESC) AS ITEM_RK FROM RB_OB_INFO HD INNER JOIN OB_BASE DT ON HD.CTKEY = DT.CTKEY AND HD.OWKEY = DT.OWKEY AND HD.RB_OBHDKEY = DT.OBHDKEY AND DT.ORDSEPTYPECD = '30' GROUP BY DT.CTKEY , DT.OWKEY , DT.ICKEY , HD.RB_BOXNM ), RB_HD_MATCH AS ( /* [2단계] 품목 우선순위별로, 그 품목을 포함한 헤더-규격 조합 매핑 */ SELECT HD.CTKEY , HD.OWKEY , HD.RB_OBHDKEY , HD.RB_BOXNM , IR.ICKEY , IR.ITEM_RK FROM RB_OB_INFO HD INNER JOIN OB_BASE DT ON HD.CTKEY = DT.CTKEY AND HD.OWKEY = DT.OWKEY AND HD.RB_OBHDKEY = DT.OBHDKEY AND DT.ORDSEPTYPECD = '30' INNER JOIN RB_ITEM_RANK IR ON DT.CTKEY = IR.CTKEY AND DT.OWKEY = IR.OWKEY AND DT.ICKEY = IR.ICKEY AND HD.RB_BOXNM = IR.RB_BOXNM ), RB_OB_RANK AS ( /* [3단계] 규격별로, 품목 우선순위를 기준으로 헤더 순위를 매김 */ SELECT OBINFO.CTKEY , OBINFO.OWKEY , OBINFO.RB_OBHDKEY , OBINFO.RB_BOXNM , OBINFO.CBM , OBINFO.WEIGHT , OBINFO.MAXLEN , OBINFO.SKU , OBINFO.PCS , OBINFO.OBDT_CNT , OB.RK FROM ( SELECT CTKEY , OWKEY , RB_OBHDKEY , RB_BOXNM , MIN(ITEM_RK) AS BEST_ITEM_RK -- 헤더가 가진 품목 중 가장 높은 우선순위 , ROW_NUMBER() OVER(PARTITION BY RB_BOXNM ORDER BY MIN(ITEM_RK)) AS RK FROM RB_HD_MATCH GROUP BY CTKEY, OWKEY, RB_BOXNM, RB_OBHDKEY ) OB INNER JOIN RB_OB_INFO OBINFO ON OB.CTKEY = OBINFO.CTKEY AND OB.OWKEY = OBINFO.OWKEY AND OB.RB_OBHDKEY = OBINFO.RB_OBHDKEY AND OB.RB_BOXNM = OBINFO.RB_BOXNM LEFT OUTER JOIN OB_BASE DT ON OB.CTKEY = DT.CTKEY AND OB.OWKEY = DT.OWKEY AND OB.RB_OBHDKEY = DT.OBHDKEY AND DT.ORDSEPTYPECD = '30' GROUP BY OBINFO.CTKEY , OBINFO.OWKEY , OBINFO.RB_OBHDKEY , OBINFO.RB_BOXNM , OBINFO.CBM , OBINFO.WEIGHT , OBINFO.MAXLEN , OBINFO.SKU , OBINFO.PCS , OBINFO.OBDT_CNT , OB.RK ), OB_RB AS ( SELECT OB.CTKEY , OB.OWKEY , DT.OBORDKEY AS RB_OBORDKEY , OB.RB_OBHDKEY , OB.RB_BOXNM , OB.CBM , OB.WEIGHT , DT.CLASSIFSPECCD , DT.RECOMBOXBARCODE , OB.MAXLEN , OB.SKU , OB.PCS AS RB_PCS , OB.OBDT_CNT , OB.RK FROM ( SELECT CTKEY , OWKEY , RB_OBHDKEY , RB_BOXNM , CBM , WEIGHT , MAXLEN , SKU , PCS , OBDT_CNT , RK
FROM RB_OB_INFO
FROM RB_OB_RANK
WHERE RB_BOXNM = #{boxnm}
WHERE 1 = 2
) OB LEFT OUTER JOIN OB_BASE DT ON OB.CTKEY = DT.CTKEY AND OB.OWKEY = DT.OWKEY AND OB.RB_OBHDKEY = DT.OBHDKEY AND DT.ORDSEPTYPECD = '30' GROUP BY OB.CTKEY , OB.OWKEY , DT.OBORDKEY , OB.RB_OBHDKEY , OB.RB_BOXNM , OB.CBM , OB.WEIGHT , DT.CLASSIFSPECCD , DT.RECOMBOXBARCODE , OB.MAXLEN , OB.SKU , OB.PCS , OB.OBDT_CNT , OB.RK ), MX_OB_INFO AS ( SELECT A.* , ROW_NUMBER() OVER(PARTITION BY MX_BOXNM ORDER BY MX_BOXNM, MX_OBHDKEY ASC) AS RK FROM ( SELECT CTKEY , OWKEY , OBHDKEY AS MX_OBHDKEY /*릴리즈코드*/ , BOXNM AS MX_BOXNM , CBM , WEIGHT , COUNT(ICKEY) AS SKU , SUM(EXPCTQTY) AS PCS , MAX(MAXLEN) AS MAXLEN , ROUND(COUNT(CASE WHEN ROBSORTERICYN = 'Y' THEN 1 END) * 100 / COUNT(*), 0) AS RBRATIO , SUM(CASE WHEN ROBSORTERICYN = 'N' THEN EXPCTQTY ELSE 0 END) AS FBPCS , COUNT(OBDTKEY) AS OBDT_CNT FROM OB_BASE WHERE ORDSEPTYPECD = '40' GROUP BY CTKEY , OWKEY , OBHDKEY /*릴리즈코드*/ , BOXNM , CBM , WEIGHT ) A WHERE 1=1
), MX_ITEM_RANK AS ( /* [1단계] 품목코드별 등장 건수 순위 */ SELECT DT.CTKEY , DT.OWKEY , DT.ICKEY , HD.MX_BOXNM , COUNT(DISTINCT DT.OBHDKEY) AS OBHD_CNT , ROW_NUMBER() OVER(PARTITION BY HD.MX_BOXNM ORDER BY COUNT(DISTINCT DT.OBHDKEY) DESC) AS ITEM_RK FROM MX_OB_INFO HD INNER JOIN OB_BASE DT ON HD.CTKEY = DT.CTKEY AND HD.OWKEY = DT.OWKEY AND HD.MX_OBHDKEY = DT.OBHDKEY AND DT.ORDSEPTYPECD = '40' GROUP BY DT.CTKEY , DT.OWKEY , DT.ICKEY , HD.MX_BOXNM ), MX_HD_MATCH AS ( /* [2단계] 품목 우선순위별로, 그 품목을 포함한 헤더-규격 조합 매핑 */ SELECT HD.CTKEY , HD.OWKEY , HD.MX_OBHDKEY , HD.MX_BOXNM , IR.ICKEY , IR.ITEM_RK FROM MX_OB_INFO HD INNER JOIN OB_BASE DT ON HD.CTKEY = DT.CTKEY AND HD.OWKEY = DT.OWKEY AND HD.MX_OBHDKEY = DT.OBHDKEY AND DT.ORDSEPTYPECD = '40' INNER JOIN MX_ITEM_RANK IR ON DT.CTKEY = IR.CTKEY AND DT.OWKEY = IR.OWKEY AND DT.ICKEY = IR.ICKEY AND HD.MX_BOXNM = IR.MX_BOXNM ), MX_OB_RANK AS ( /* [3단계] 규격별로, 품목 우선순위를 기준으로 헤더 순위를 매김 */ SELECT OBINFO.CTKEY , OBINFO.OWKEY , OBINFO.MX_OBHDKEY , OBINFO.MX_BOXNM , OBINFO.CBM , OBINFO.WEIGHT , DT.RECOMBOXBARCODE , OBINFO.MAXLEN , OBINFO.SKU , OBINFO.PCS , OBINFO.OBDT_CNT , OB.RK FROM ( SELECT CTKEY , OWKEY , MX_OBHDKEY , MX_BOXNM , MIN(ITEM_RK) AS BEST_ITEM_RK -- 헤더가 가진 품목 중 가장 높은 우선순위 , ROW_NUMBER() OVER(PARTITION BY MX_BOXNM ORDER BY MIN(ITEM_RK)) AS RK FROM MX_HD_MATCH GROUP BY CTKEY, OWKEY, MX_BOXNM, MX_OBHDKEY ) OB INNER JOIN MX_OB_INFO OBINFO ON OB.CTKEY = OBINFO.CTKEY AND OB.OWKEY = OBINFO.OWKEY AND OB.MX_OBHDKEY = OBINFO.MX_OBHDKEY AND OB.MX_BOXNM = OBINFO.MX_BOXNM LEFT OUTER JOIN OB_BASE DT ON OB.CTKEY = DT.CTKEY AND OB.OWKEY = DT.OWKEY AND OB.MX_OBHDKEY = DT.OBHDKEY AND DT.ORDSEPTYPECD = '40' GROUP BY OBINFO.CTKEY , OBINFO.OWKEY , OBINFO.MX_OBHDKEY , OBINFO.MX_BOXNM , OBINFO.CBM , OBINFO.WEIGHT , DT.RECOMBOXBARCODE , OBINFO.MAXLEN , OBINFO.SKU , OBINFO.PCS , OBINFO.OBDT_CNT , OB.RK ), OB_MX AS ( SELECT OB.CTKEY , OB.OWKEY , DT.OBORDKEY AS MX_OBORDKEY , OB.MX_OBHDKEY , OB.MX_BOXNM , OB.CBM , OB.WEIGHT , DT.CLASSIFSPECCD , DT.RECOMBOXBARCODE , OB.MAXLEN , OB.SKU , OB.PCS AS MX_PCS , OB.OBDT_CNT , OB.RK FROM ( SELECT CTKEY , OWKEY , MX_OBHDKEY , MX_BOXNM , CBM , WEIGHT , MAXLEN , SKU , PCS , OBDT_CNT , RK
FROM MX_OB_INFO
FROM MX_OB_RANK
WHERE MX_BOXNM = #{boxnm}
WHERE 1 = 2
) OB LEFT OUTER JOIN OB_BASE DT ON OB.CTKEY = DT.CTKEY AND OB.OWKEY = DT.OWKEY AND OB.MX_OBHDKEY = DT.OBHDKEY AND DT.ORDSEPTYPECD = '40' GROUP BY OB.CTKEY , OB.OWKEY , DT.OBORDKEY , OB.MX_OBHDKEY , OB.MX_BOXNM , OB.CBM , OB.WEIGHT , DT.CLASSIFSPECCD , DT.RECOMBOXBARCODE , OB.MAXLEN , OB.SKU , OB.PCS , OB.OBDT_CNT , OB.RK ), OB_MX_RB AS ( SELECT MX.CTKEY , MX.OWKEY , MX.MX_OBHDKEY AS MX_RB_OBHDKEY , MX.MX_BOXNM , MX.CBM , MX.WEIGHT , OB.RECOMBOXBARCODE , MX.MAXLEN , MX.SKU , MX.MX_PCS AS MX_RB_PCS , MX.OBDT_CNT , MX.RK FROM OB_MX MX INNER JOIN OB_BASE OB ON MX.CTKEY = OB.CTKEY AND MX.OWKEY = OB.OWKEY AND MX.MX_OBHDKEY = OB.OBHDKEY AND OB.ORDSEPTYPECD = '40' AND OB.ROBSORTERICYN = 'Y' GROUP BY MX.CTKEY , MX.OWKEY , MX.MX_OBHDKEY , MX.MX_BOXNM , MX.CBM , MX.WEIGHT , OB.RECOMBOXBARCODE , MX.MAXLEN , MX.SKU , MX.MX_PCS , MX.OBDT_CNT , MX.RK ), OB_MX_FB AS ( SELECT MX.CTKEY , MX.OWKEY , MX.MX_OBHDKEY AS MX_FB_OBHDKEY , MX.MX_BOXNM , MX.CBM , MX.WEIGHT , OB.RECOMBOXBARCODE , MX.MAXLEN , MX.SKU , MX.MX_PCS AS MX_FB_PCS , MX.OBDT_CNT , MX.RK FROM OB_MX MX INNER JOIN OB_BASE OB ON MX.CTKEY = OB.CTKEY AND MX.OWKEY = OB.OWKEY AND MX.MX_OBHDKEY = OB.OBHDKEY AND OB.ORDSEPTYPECD = '40' AND OB.ROBSORTERICYN = 'N' GROUP BY MX.CTKEY , MX.OWKEY , MX.MX_OBHDKEY , MX.MX_BOXNM , MX.CBM , MX.WEIGHT , OB.RECOMBOXBARCODE , MX.MAXLEN , MX.SKU , MX.MX_PCS , MX.OBDT_CNT , MX.RK ), RB_SKU AS ( SELECT RB.CTKEY , RB.OWKEY , RB.RB_BOXNM , COUNT(DISTINCT ICKEY) AS RSLT_RB_SKU FROM OB_RB RB INNER JOIN OB_BASE OB ON RB.CTKEY = OB.CTKEY AND RB.OWKEY = OB.OWKEY AND RB.RB_OBHDKEY = OB.OBHDKEY AND RB.RB_BOXNM = OB.BOXNM AND OB.ORDSEPTYPECD = '30' GROUP BY RB.CTKEY , RB.OWKEY , RB.RB_BOXNM ), MX_SKU AS ( SELECT MX.CTKEY , MX.OWKEY , MX.MX_BOXNM , COUNT(DISTINCT ICKEY) AS RSLT_MX_SKU FROM OB_MX MX INNER JOIN OB_BASE OB ON MX.CTKEY = OB.CTKEY AND MX.OWKEY = OB.OWKEY AND MX.MX_OBHDKEY = OB.OBHDKEY AND MX.MX_BOXNM = OB.BOXNM AND OB.ORDSEPTYPECD = '40' GROUP BY MX.CTKEY , MX.OWKEY , MX.MX_BOXNM ), MX_RB_SKU AS ( SELECT MXRB.CTKEY , MXRB.OWKEY , MXRB.MX_BOXNM , COUNT(DISTINCT ICKEY) AS RSLT_MX_RB_SKU FROM OB_MX_RB MXRB INNER JOIN OB_BASE OB ON MXRB.CTKEY = OB.CTKEY AND MXRB.OWKEY = OB.OWKEY AND MXRB.MX_RB_OBHDKEY = OB.OBHDKEY AND MXRB.MX_BOXNM = OB.BOXNM AND OB.ORDSEPTYPECD = '40' AND OB.ROBSORTERICYN = 'Y' GROUP BY MXRB.CTKEY , MXRB.OWKEY , MXRB.MX_BOXNM ), MX_FB_SKU AS ( SELECT MXFB.CTKEY , MXFB.OWKEY , MXFB.MX_BOXNM , COUNT(DISTINCT ICKEY) AS RSLT_MX_FB_SKU FROM OB_MX_FB MXFB INNER JOIN OB_BASE OB ON MXFB.CTKEY = OB.CTKEY AND MXFB.OWKEY = OB.OWKEY AND MXFB.MX_FB_OBHDKEY = OB.OBHDKEY AND MXFB.MX_BOXNM = OB.BOXNM AND OB.ORDSEPTYPECD = '40' AND ROBSORTERICYN = 'N' GROUP BY MXFB.CTKEY , MXFB.OWKEY , MXFB.MX_BOXNM )

mapper.select:
/* wms-outbound-obWaveMgmt-sql-oracle.xml - selectWaExceptionValidate - WMS > 출고 관리 > 웨이브관리 > 출고 계획 - 제외 Validate*/
SELECT COUNT(*)
  FROM TWORK_INFO_WA_HD
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND WAHDKEY = #{wahdkey}
   AND WAWKSTATUSCD IN ('00','05','10','11','15','20','25')

/* wms-outbound-obWaveMgmt-sql-oracle.xml - selectWaReAllocateValidate - WMS > 출고 관리 > 웨이브관리 > 출고 계획 - 재할당 Validate*/
SELECT COUNT(*)
  FROM TWORK_INFO_WA_HD
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND WAHDKEY = #{wahdkey}
   AND WAWKSTATUSCD IN ('00','05')

/* wms-outbound-obWaveMgmt-sql-oracle.xml - selectWaStockOutValidate - WMS > 출고 관리 > 웨이브관리 > 출고 계획 - 미할당처리 Validate*/
SELECT COUNT(*)
  FROM TWORK_INFO_WA_HD
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND WAHDKEY = #{wahdkey}
   AND WAWKSTATUSCD IN ('00','05')

/* wms-outbound-obWaveMgmt-sql-oracle.xml - selectWaUpdateValidate - WMS > 출고 관리 > 웨이브관리 > 수정 Validate*/
SELECT COUNT(*)
  FROM TWORK_INFO_WA_HD
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND WAHDKEY = #{wahdkey}
   AND WAWKSTATUSCD IN ('00','05','10','11','15','20','25')

/* wms-outbound-obWaveMgmt-sql-oracle.xml - selectWaDeleteValidate - WMS > 출고 관리 > 웨이브관리 > 삭제 Validate*/
SELECT COUNT(*)
  FROM TWORK_INFO_WA_HD
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND WAHDKEY = #{wahdkey}
   AND WAWKSTATUSCD IN ('00','05','10','11','15','20','25','30')

/* wms-outbound-obWaveMgmt-sql-oracle.xml - selectwaveMgmtPopTaskList_PkCnfrmList - WMS > 출고 관리 > 웨이브관리 > 작업현황 > 피킹리스트 > 피킹확정 - 총량 피킹의 피킹 지시 상태 리스트 조회 */
SELECT CTKEY
	 , OWKEY
	 , PIHDKEY
	 , ICKEY
	 , IVATKEY
	 , LCKEY
	 , UOM
  FROM TWORK_INFO_PI_TOT_DT
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND PIHDKEY = #{pihdkey}
   AND PKWKSTATUSCD = '00'

mapper.update:
/* wms-outbound-obWaveMgmt-sql-oracle.xml - updatewaveMgmtPopTaskList_PkCnfrmList - WMS > 출고 관리 > 웨이브관리 > 작업현황 > 피킹리스트 > 피킹확정 - 피킹확정  */
UPDATE TWORK_INFO_PI_TOT_DT
   SET PKWKSTATUSCD = '10'
	 , PKCNFRMDATE = #{sysdate}
	 , PKCNFRMURKEY = #{surkey}
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND PIHDKEY = #{pihdkey}
   AND PKWKSTATUSCD = '00'

mapper.select:
/* wms-outbound-obWaveMgmt-sql-oracle.xml - selectwaveMgmtPopTaskList_PkCnfrmCnl - WMS > 출고 관리 > 웨이브관리 > 작업현황 > 피킹리스트 > 피킹 확정 취소 - 총량 피킹의 피킹 확정 상태 조회 */
SELECT CTKEY
	 , OWKEY
	 , PIHDKEY
	 , ICKEY
	 , IVATKEY
	 , UOM
	 , LCKEY
	 , CELLKEY
	 , EXPCTQTY
	 , CNFRMQTY
	 , CNFRMQTY AS CNCLQTY
	 , #{sysdate} AS "CURRENT_TIMESTAMP"
	 , #{surkey} AS SURKEY
  FROM TWORK_INFO_PI_TOT_DT
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND PIHDKEY = #{pihdkey}
   AND ICKEY = #{ickey}
   AND IVATKEY = #{ivatkey}
   AND LCKEY = #{lckey}
   AND PKWKSTATUSCD = '10'
